const body = $input.first().json.body || $input.first().json;
const tenantId = body.tenantId;
const from = body.from || '';
const to = body.to || '';
const subject = body.subject || '';
const textPlain = body.textPlain || '';
const threadId = body.threadId || null;
const emailId = body.emailId || null;
const hasAttachments = body.hasAttachments || false;

if (!tenantId || !from) {
  return [{ json: { success: false, error: 'tenantId et from requis' } }];
}

return [{ json: {
  tenantId, from, to, subject, textPlain,
  threadId, emailId, hasAttachments,
  valid: true
} }];

const email = $('02. Valider').first().json;
const rows = $input.all().map(r => r.json);
const aiConfig = rows[0]?.ai_config || {};
const rules = rows.filter(r => r.rule_id).map(r => ({
  id: r.rule_id,
  nom: r.nom,
  type: r.type_rule,
  conditions: r.conditions,
  actionType: r.action_type,
  actionConfig: r.action_config,
  priorite: r.priorite
}));

// --- Etape 1 : Matcher les regles statiques ---
let matchedRule = null;
for (const rule of rules) {
  const cond = rule.conditions || {};
  let match = true;

  if (cond.from_contains && !email.from.toLowerCase().includes(cond.from_contains.toLowerCase())) match = false;
  if (cond.subject_contains && !email.subject.toLowerCase().includes(cond.subject_contains.toLowerCase())) match = false;
  if (cond.body_contains && !email.textPlain.toLowerCase().includes(cond.body_contains.toLowerCase())) match = false;
  if (cond.from_domain) {
    const domain = email.from.split('@')[1]?.split('>')[0] || '';
    if (domain.toLowerCase() !== cond.from_domain.toLowerCase()) match = false;
  }

  if (match && rule.type === 'static') {
    matchedRule = rule;
    break;
  }
}

return [{ json: {
  ...email,
  aiConfig,
  rules,
  matchedRule,
  needsAI: !matchedRule,
  aiModel: aiConfig.model || 'gpt-4o-mini',
  aiApiKey: aiConfig.openaiApiKey || '',
  businessContext: aiConfig.businessContext || '',
  language: aiConfig.language || 'fr',
  tone: aiConfig.tone || 'professionnel'
} }];

