const email = $('04. Verifier regles statiques').first().json;
const aiResponse = $input.first().json;

let classification = {};
try {
  const content = aiResponse.choices?.[0]?.message?.content || '{}';
  classification = JSON.parse(content);
} catch (e) {
  classification = {
    categorie: 'autre',
    priorite: 'normale',
    sentiment: 'neutre',
    intention: 'autre',
    auto_repondable: false,
    resume: 'Classification echouee',
    tags: []
  };
}

const action = classification.auto_repondable ? 'auto_reply' : 'queue_human';

return [{ json: {
  ...email,
  classification,
  action,
  source: 'ai',
  tokensUsed: aiResponse.usage?.total_tokens || 0
} }];

const email = $('04. Verifier regles statiques').first().json;
const rule = email.matchedRule;

return [{ json: {
  ...email,
  classification: {
    categorie: rule.actionConfig?.categorie || 'autre',
    priorite: rule.actionConfig?.priorite || 'normale',
    sentiment: 'neutre',
    intention: rule.actionConfig?.intention || 'autre',
    auto_repondable: rule.actionType === 'auto_reply',
    resume: `Regle appliquee: ${rule.nom}`,
    tags: rule.actionConfig?.tags || []
  },
  action: rule.actionType,
  source: 'rule',
  matchedRuleId: rule.id,
  tokensUsed: 0
} }];

const prev = $('07. Parser resultat IA').first()?.json || $('06b. Appliquer regle').first()?.json;
const saved = $input.first().json;

return [{ json: {
  success: true,
  data: {
    incomingLogId: saved.id || null,
    action: prev.action,
    classification: prev.classification,
    source: prev.source,
    tenantId: prev.tenantId,
    from: prev.from,
    subject: prev.subject,
    emailId: prev.emailId,
    threadId: prev.threadId
  }
} }];
